import { useQuery } from '@tanstack/react-query';
import { useAuth } from './useAuth';
import { getKYCStatus } from '@/services/kyc.service';
import { useEffect, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { decryptSensitiveData } from '@/lib/crypto';
import { useToast } from './use-toast';

export const useKYC = () => {
    const { user } = useAuth();
    const { toast } = useToast();
    const prevStatusRef = useRef<string | null>(null);

    const { data: kycData, isLoading, isFetching, error, refetch } = useQuery({
        queryKey: ['kycStatus', user?.id],
        queryFn: async () => {
            if (!user) return null;
            const data = await getKYCStatus(user.id) as any;
            if (!data) return null;

            // Decrypt numbers for convenience if data exists
            try {
                const [pan, aadhar] = await Promise.all([
                    decryptSensitiveData(data.pan_number),
                    decryptSensitiveData(data.aadhar_number)
                ]);
                return { ...data, decrypted_pan: pan, decrypted_aadhar: aadhar };
            } catch (err) {
                console.warn("[useKYC] Failed to decrypt data:", err);
                return data;
            }
        },
        enabled: !!user,
        staleTime: 0,
    });

    const status = kycData?.status || null; // 'APPROVED' | 'PENDING' | 'REJECTED' | null

    // Notify on approval
    useEffect(() => {
        if (prevStatusRef.current === 'PENDING' && status === 'APPROVED') {
            toast({
                title: "KYC Approved! ≡ƒÄë",
                description: "Your account is now verified. You can now add up to Γé╣5,000 to your wallet and access full services.",
            });
        }
        prevStatusRef.current = status;
    }, [status, toast]);

    // REAL-TIME: Listen for changes to current user's KYC record
    useEffect(() => {
        if (!user) return;

        const channel = supabase
            .channel(`kyc_status_${user.id}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'kyc_verifications',
                    filter: `user_id=eq.${user.id}`
                },
                () => {
                    console.log('[useKYC] State change detected, refetching...');
                    refetch();
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [user?.id, refetch]);

    const isApproved = status === 'APPROVED';
    const isPending = status === 'PENDING';
    const isRejected = status === 'REJECTED';

    console.log('[useKYC] Hook State:', { userId: user?.id, status, isLoading, kycData });

    return {
        kycData,
        status,
        isApproved,
        isPending,
        isRejected,
        // Consolidate loading state:
        // If user exists, but we don't have data or error, consider it loading.
        // This prevents early redirects before the query fires or returns.
        isLoading: !!user && (isLoading || (kycData === undefined && !error)),
        error,
        refetch
    };
};

import { useEffect, useState } from "react";
import { useNavigate, useLocation, Outlet } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Loader2, LayoutDashboard, Users, Receipt, Wallet, Settings, LogOut, Shield } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Toaster } from "@/components/ui/sonner";

const AdminLayout = () => {
    const navigate = useNavigate();
    const location = useLocation();
    const [loading, setLoading] = useState(true);
    const [isAdmin, setIsAdmin] = useState(false);

    useEffect(() => {
        checkAdmin();
    }, []);

    const checkAdmin = async () => {
        try {
            // @ts-ignore - Supabase types might be mismatching in this env
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) {
                navigate("/auth");
                return;
            }

            // Check role
            const { data: roleData, error } = await supabase
                .from('user_roles')
                .select('role')
                .eq('user_id', session.user.id)
                .single();

            if (error || roleData?.role !== 'admin') {
                console.error("Access denied:", error);
                navigate("/"); // Redirect to home if not admin
                return;
            }

            setIsAdmin(true);
        } catch (err) {
            console.error(err);
            navigate("/");
        } finally {
            setLoading(false);
        }
    };

    const handleLogout = async () => {
        // @ts-ignore
        await supabase.auth.signOut();
        navigate("/auth");
    };

    if (loading) {
        return <div className="h-screen w-full flex items-center justify-center"><Loader2 className="h-8 w-8 animate-spin" /></div>;
    }

    if (!isAdmin) return null;

    const navItems = [
        { icon: LayoutDashboard, label: "Dashboard", path: "/admin" },
        { icon: Shield, label: "KYC Requests", path: "/admin/kyc" },
        { icon: Users, label: "User Management", path: "/admin/users" },
        { icon: Receipt, label: "Transactions", path: "/admin/transactions" },
        { icon: Wallet, label: "Commissions", path: "/admin/commissions" },
        // { icon: Settings, label: "Settings", path: "/admin/settings" },
    ];

    return (
        <div className="flex h-screen bg-gray-100">
            {/* Sidebar */}
            <aside className="w-64 bg-slate-900 text-white flex flex-col">
                <div className="p-6">
                    <h1 className="text-2xl font-bold bg-gradient-to-r from-blue-400 to-purple-500 bg-clip-text text-transparent">
                        Prepe Admin
                    </h1>
                </div>

                <nav className="flex-1 px-4 space-y-2">
                    {navItems.map((item) => (
                        <button
                            key={item.path}
                            onClick={() => navigate(item.path)}
                            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${location.pathname === item.path
                                ? "bg-blue-600 text-white"
                                : "text-slate-400 hover:bg-slate-800 hover:text-white"
                                }`}
                        >
                            <item.icon className="h-5 w-5" />
                            <span className="font-medium">{item.label}</span>
                        </button>
                    ))}
                </nav>

                <div className="p-4 border-t border-slate-800">
                    <Button
                        variant="ghost"
                        className="w-full justify-start text-red-400 hover:text-red-300 hover:bg-red-900/20"
                        onClick={handleLogout}
                    >
                        <LogOut className="mr-2 h-4 w-4" />
                        Logout
                    </Button>
                </div>
            </aside>

            {/* Main Content */}
            <main className="flex-1 overflow-auto">
                <div className="p-8">
                    <Outlet />
                </div>
            </main>
            <Toaster />
        </div>
    );
};

