                            </div>
                            <div className="h-px w-full bg-slate-200/50" />
                            <div className="flex justify-between items-center">
                                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">Refund Amount</span>
                                <span className="font-black text-lg text-rose-600">Γé╣{selectedTxn?.amount}</span>
                            </div>
                        </div>
                        <div className="space-y-2">
                            <Label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Reason for Refund</Label>
                            <Textarea
                                placeholder="e.g. Transaction timed out / Customer request via support ticket"
                                value={refundReason}
                                onChange={(e) => setRefundReason(e.target.value)}
                                className="min-h-[100px] resize-none rounded-xl bg-slate-50 border-slate-200 focus:bg-white focus:border-rose-400 transition-colors font-medium"
                            />
                        </div>
                    </div>
                    <DialogFooter className="mt-6 gap-3 sm:gap-0">
                        <Button variant="ghost" onClick={() => setRefundDialog(false)} className="rounded-xl font-semibold text-slate-500 h-11 hover:bg-slate-100">
                            Cancel
                        </Button>
                        <Button
                            variant="destructive"
                            onClick={handleRefund}
                            disabled={processing || !refundReason.trim()}
                            className="rounded-xl font-bold h-11 px-6 bg-rose-600 hover:bg-rose-700 shadow-md shadow-rose-600/20 transition-all"
                        >
                            {processing ? <Loader2 className="mr-2 h-5 w-5 animate-spin" /> : null}
                            Confirm Refund
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
};

