    TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Loader2, Search, Ban, CheckCircle, CreditCard, History, MoreVertical } from "lucide-react";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";

const UserManagement = () => {
    const [users, setUsers] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState("");
    const [page, setPage] = useState(1);
    const [selectedUser, setSelectedUser] = useState<any>(null);
    const [walletDialog, setWalletDialog] = useState(false);

    // Wallet Adjustment Form
    const [adjType, setAdjType] = useState<'CREDIT' | 'DEBIT'>('CREDIT');
    const [adjAmount, setAdjAmount] = useState("");
    const [adjReason, setAdjReason] = useState("");
    const [submitting, setSubmitting] = useState(false);

    useEffect(() => {
        fetchUsers();
    }, [page, search]);

    const fetchUsers = async () => {
        setLoading(true);
        try {
            const { data } = await adminService.getUsers(page, 20, search);
            setUsers(data || []);
        } catch (e) {
            toast.error("Failed to load users");
        } finally {
            setLoading(false);
        }
    };

    const handleWalletAdjustment = async () => {
        if (!selectedUser || !adjAmount || !adjReason) return;
        setSubmitting(true);
        try {
            await adminService.adjustWallet(selectedUser.user_id, adjType, Number(adjAmount), adjReason);
            toast.success("Wallet adjusted successfully");
            setWalletDialog(false);
            fetchUsers();
            setAdjAmount("");
            setAdjReason("");
        } catch (e: any) {
            toast.error(e.message || "Adjustment failed");
        } finally {
            setSubmitting(false);
        }
    };

