                                                        onClick={() => { setSelectedUser(user); setWalletDialog(true); }}
                                                    >
                                                        <CreditCard className="h-4 w-4 mr-1.5" /> Adjust Balance
                                                    </Button>
                                                </div>
                                            </TableCell>
                                        </TableRow>
                                    ))
                                )}
